import { BUTTON_VARIANT_TERTIARY } from '#components/Button/Button.constants';

import {
  INITIAL_MAX_SELECTED_ITEMS,
  SELECTED_LIST_TESTID,
  STATUS_TESTID,
} from './Controls.constants';
import {
  Boundary,
  Inner,
  Buttons,
  Status,
  SelectedList,
  SelectedItem,
  Title,
  Image,
  Button,
} from './Controls.styles';
import { ControlsProps } from './Controls.types';

const Controls = (props: ControlsProps) => {
  const {
    selectedItems = [],
    max = INITIAL_MAX_SELECTED_ITEMS,
    onReset,
    onCompare,
  } = props;
  const clampedSelectedItems = selectedItems.slice(0, max);

  return (
    <Boundary>
      <Inner>
        <SelectedList data-testid={SELECTED_LIST_TESTID}>
          {clampedSelectedItems.map(({ title, image }, index) => (
            <SelectedItem key={index}>
              <Title>{title}</Title>
              <Image src={image} alt="Product image" />
            </SelectedItem>
          ))}
        </SelectedList>
        <Buttons>
          <Button
            variant={BUTTON_VARIANT_TERTIARY}
            type="reset"
            disabled={clampedSelectedItems.length < 1}
            onClick={onReset}
          >
            Clear
          </Button>
          <Button
            disabled={clampedSelectedItems.length < 2}
            onClick={onCompare}
          >
            Compare
            <Status data-testid={STATUS_TESTID}>
              ({clampedSelectedItems.length}/{max})
            </Status>
          </Button>
        </Buttons>
      </Inner>
    </Boundary>
  );
};

export default Controls;
